package Welcome;

public class Logicaloranbitwise {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a =10;
		int b=20;
		System.out.println(a>b || ++a >b);  //only checks the first condtion
		System.out.println(a);
		
		System.out.println(a<b | ++a >b);
		System.out.println(a);

	}

}
